mapper.select:
SELECT e.execution_id, e.script_id, e.execution_name, e.execution_status, e.start_time, e.end_time, e.duration, e.execution_result, e.error_message, e.execution_params, e.executor_id, e.enterprise_id, e.create_time, e.update_time, s.script_name, u.user_name AS executor_name FROM datacloud_script_execution e LEFT JOIN datacloud_script s ON e.script_id = s.script_id LEFT JOIN sys_user u ON e.executor_id = u.user_id WHERE e.enterprise_id = #{query.enterpriseId}
AND e.script_id = #{query.scriptId}
AND e.execution_status = #{query.executionStatus}
AND e.executor_id = #{query.executorId}
AND e.start_time >= #{query.startTimeBegin}
AND e.start_time <= #{query.startTimeEnd}
ORDER BY e.start_time DESC

SELECT e.execution_id, e.script_id, e.execution_name, e.execution_status, e.start_time, e.end_time, e.duration, e.execution_result, e.error_message, e.execution_params, e.executor_id, e.enterprise_id, e.create_time, e.update_time, s.script_name, u.user_name AS executor_name FROM datacloud_script_execution e LEFT JOIN datacloud_script s ON e.script_id = s.script_id LEFT JOIN sys_user u ON e.executor_id = u.user_id WHERE e.execution_status = 'running'
AND e.script_id = #{scriptId}
AND e.enterprise_id = #{enterpriseId} ORDER BY e.start_time DESC

SELECT COUNT(*)
FROM datacloud_script_execution
WHERE script_id = #{scriptId}

SELECT MAX(start_time)
FROM datacloud_script_execution
WHERE script_id = #{scriptId}

